def adjacency_matrix(graph):
    """Convert a graph to an adjacency matrix representation"""
    n = len(graph)
    adj_matrix = [[0] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if graph[i][j]:
                adj_matrix[i][j] = 1
    return adj_matrix


